@@ -1,8 +1,51 @@
 const express = require('express');
 const router = express.Router();
 const fs = require('fs');
 const path = require('path');
+const crypto = require('crypto');
 const { authenticate } = require('../middleware/auth');
+const { saveFileRecord } = require('../services/file-service');
+
+const UPLOAD_DIR = path.join(__dirname, '../../uploads');
+const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/gif', 'application/pdf'];
+
+router.post('/upload', authenticate, async (req, res) => {
+  try {
+    if (!req.files || !req.files.attachment) {
+      return res.status(400).json({ error: 'No file provided' });
+    }
+
+    const file = req.files.attachment;
+
+    if (!ALLOWED_TYPES.includes(file.mimetype)) {
+      return res.status(400).json({ error: 'File type not allowed' });
+    }
+
+    const ext = path.extname(file.name);
+    const destPath = path.join(UPLOAD_DIR, file.name);
+
+    const tempPath = path.join(UPLOAD_DIR, `tmp_${crypto.randomUUID()}${ext}`);
+    await fs.promises.writeFile(tempPath, file.data);
+
+    await fs.promises.rename(tempPath, destPath);
+
+    const record = await saveFileRecord({
+      userId: req.user.id,
+      filename: file.name,
+      mimetype: file.mimetype,
+      size: file.data.length,
+      path: destPath,
+    });
+
+    return res.status(201).json({
+      id: record.id,
+      filename: file.name,
+      url: `/uploads/${file.name}`,
+    });
+  } catch (err) {
+    console.error('Upload failed:', err);
+    return res.status(500).json({ error: 'Upload failed' });
+  }
+});

-// TODO: implement file uploads
+if (!fs.existsSync(UPLOAD_DIR)) {
+  fs.mkdirSync(UPLOAD_DIR, { recursive: true });
+}

 module.exports = router;
```

Write a WebSocket message handler for the Paloma bridge that processes incoming messages from the browser. The handler should support these message types:

1. `chat` — sends user message to a CLI session (calls `cliManager.chat()`)
2. `ask_user_response` — resolves a pending ask_user request from a Map
3. `tool_confirm_response` — resolves a pending tool confirmation from a Map

Use this pattern from the existing bridge:
```javascript
// Pending request tracking
const pendingAskUser = new Map()    // id → { resolve, createdAt }
const pendingToolConfirm = new Map() // id → { resolve, createdAt }

ws.on('message', (raw) => {
  let msg
  try {
    msg = JSON.parse(raw)
  } catch {
    ws.send(JSON.stringify({ type: 'error', error: 'Invalid JSON' }))
    return
  }
  // Handle msg.type...
})
```

For `chat`, generate a requestId via `randomUUID()`, store the ws→requestId mapping in `cliRequestToWs`, and call `cliManager.chat({ prompt: msg.prompt, model: msg.model, sessionId: msg.sessionId })` with an event callback that sends events back to the originating ws client.

For ask_user/tool responses, look up the pending Map entry by `msg.id`, call its `resolve(msg.response)`, and delete the entry.

```javascript
// Pending request tracking
const pendingAskUser = new Map()    // id → { resolve, createdAt }
const pendingToolConfirm = new Map() // id → { resolve, createdAt }
const cliRequestToWs = new Map()    // requestId → ws

ws.on('message', (raw) => {
  let msg
  try {
    msg = JSON.parse(raw)
  } catch {
    ws.send(JSON.stringify({ type: 'error', error: 'Invalid JSON' }))
    return
  }

  switch (msg.type) {
    case 'chat': {
      const requestId = randomUUID()
      cliRequestToWs.set(requestId, ws)

      cliManager.chat({
        prompt: msg.prompt,
        model: msg.model,
        sessionId: msg.sessionId
      }, (event) => {
        // Send event back to the originating client
        const clientWs = cliRequestToWs.get(requestId)
        if (clientWs && clientWs.readyState === WebSocket.OPEN) {
          clientWs.send(JSON.stringify({
            type: 'chat_response',
            requestId,
            ...event
          }))
        }
      })
      break
    }

    case 'ask_user_response': {
      const pending = pendingAskUser.get(msg.id)
      if (pending) {
        pending.resolve(msg.response)
        pendingAskUser.delete(msg.id)
      } else {
        ws.send(JSON.stringify({ 
          type: 'error', 
          error: 'No pending ask_user request found for id: ' + msg.id 
        }))
      }
      break
    }

    case 'tool_confirm_response': {
      const pending = pendingToolConfirm.get(msg.id)
      if (pending) {
        pending.resolve(msg.response)
        pendingToolConfirm.delete(msg.id)
      } else {
        ws.send(JSON.stringify({ 
          type: 'error', 
          error: 'No pending tool_confirm request found for id: ' + msg.id 
        }))
      }
      break
    }

    default:
      ws.send(JSON.stringify({ 
        type: 'error', 
        error: 'Unknown message type: ' + msg.type 
      }))
  }
})
```

Review the following code change (diff) and identify any issues:

```diff
diff --git a/src/services/payment-processor.js b/src/services/payment-processor.js
index 1e4a8b2..c9d3f17 100644
--- a/src/services/payment-processor.js
+++ b/src/services/payment-processor.js
@@ -1,18 +1,42 @@
 const axios = require('axios');
 const logger = require('../utils/logger');
+const { PaymentError } = require('../errors');

 class PaymentProcessor {
   constructor(apiKey) {
     this.client = axios.create({
       baseURL: 'https://api.stripe.com/v1',
       headers: { Authorization: `Bearer ${apiKey}` },
+      timeout: 10000,
     });
   }

-  async chargeCustomer(customerId, amount, currency) {
-    const response = await this.client.post('/charges', {
-      customer: customerId,
-      amount,
-      currency,
-    });
-    return response.data;
+  async chargeCustomer(customerId, amount, currency, idempotencyKey) {
+    let lastError;
+
+    while (true) {
+      try {
+        const response = await this.client.post('/charges', {
+          customer: customerId,
+          amount,
+          currency,
+        }, {
+          headers: { 'Idempotency-Key': idempotencyKey },
+        });
+
+        logger.info('Payment successful', { customerId, amount, chargeId: response.data.id });
+        return response.data;
+      } catch (e) {
+        lastError = e;
+        logger.warn('Payment attempt failed, retrying...', { customerId, amount });
+        await this._sleep(1000);
+      }
+    }
+
+    throw new PaymentError('Payment failed after retries', { cause: lastError });
+  }
+
+  _sleep(ms) {
+    return new Promise(resolve => setTimeout(resolve, ms));
   }
 }
```

## Summary of Issues

This diff introduces several critical problems including infinite loop with no exit condition, potential security vulnerabilities from hardcoded timeouts, and a flawed retry mechanism that could lead to resource exhaustion. The most severe issue is the infinite loop that will cause the application to hang indefinitely.

## Critical Issues

### 1. **Infinite Loop with No Exit Condition** (Lines 15-28)
**Impact**: This creates an infinite loop that will never terminate, causing the application to hang indefinitely and consume unlimited resources.

```javascript
while (true) {
  try {
    // ... payment logic
  } catch (e) {
    lastError = e;
    logger.warn('Payment attempt failed, retrying...', { customerId, amount });
    await this._sleep(1000);
  }
}
```

**Fix**: Add a maximum retry limit to prevent infinite loops:
```javascript
const MAX_RETRIES = 3;
let retries = 0;

while (retries < MAX_RETRIES) {
  // ... existing logic
  retries++;
}
```

### 2. **Missing Return Statement in Loop** (Lines 15-28)
**Impact**: The code will never reach the `throw new PaymentError(...)` line because the loop never exits, making the error handling unreachable.

## High Severity Issues

### 3. **Potential Security Vulnerability - Hardcoded Timeout** (Line 9)
**Impact**: Hardcoding timeout values makes the system less flexible and potentially vulnerable to DoS attacks if not properly configured for the environment.

**Recommendation**: Make timeout configurable via environment variables:
```javascript
timeout: process.env.PAYMENT_TIMEOUT || 10000,
```

### 4. **Incorrect Idempotency Key Usage** (Lines 20-27)
**Impact**: The idempotency key is being passed in the request headers but not used for the actual retry mechanism, and there's no validation of whether retries should be attempted.

## Medium Severity Issues

### 5. **Inefficient Retry Strategy** (Lines 19-27)
**Impact**: Simple exponential backoff with fixed 1-second delays is inefficient and may cause unnecessary load on the payment processor.

**Recommendation**: Implement exponential backoff:
```javascript
await this._sleep(Math.pow(2, retries) * 1000);
```

### 6. **Missing Input Validation** (Lines 15-28)
**Impact**: No validation of input parameters like `customerId`, `amount`, or `currency` could lead to unexpected behavior or errors.

**Recommendation**: Add parameter validation:
```javascript
if (!customerId || !amount || !currency) {
  throw new PaymentError('Missing required payment parameters');
}
```

### 7. **Inconsistent Error Handling** (Lines 19-27)
**Impact**: The code catches all errors but doesn't distinguish between different types of failures (network, timeout, authentication, etc.).

**Recommendation**: Implement more granular error handling:
```javascript
if (e.code === 'ECONNABORTED' || e.response?.status === 408) {
  // Handle timeout specifically
} else if (e.response?.status === 402) {
  // Handle payment required
}
```

## Style/Maintainability Concerns

### 8. **Lack of Documentation** (Lines 15-28)
**Impact**: The retry logic and error handling are not documented, making the code difficult to understand and maintain.

**Recommendation**: Add JSDoc comments explaining the retry mechanism and expected behavior.

### 9. **No Test Coverage for Retry Logic** (Lines 15-28)
**Impact**: The new retry functionality has no test coverage, increasing risk of regressions.

**Recommendation**: Add unit tests specifically for the retry mechanism with different failure scenarios.

## Overall Assessment

This change introduces a critical infinite loop that will cause application crashes and resource exhaustion. The retry mechanism needs significant improvement in terms of robustness, efficiency, and error handling. The code requires immediate attention to address these fundamental issues before deployment.

Write a JavaScript function `deepMerge(target, ...sources)` that recursively merges objects. Rules:
- Plain objects are merged recursively
- Arrays are concatenated, not replaced
- Primitives from later sources overwrite earlier ones
- The original target is not mutated (return a new object)

Include this test code at the end:

const a = { x: 1, nested: { a: 1, b: [1, 2] }, arr: [1] };
const b = { x: 2, nested: { b: [3, 4], c: 3 }, arr: [2, 3] };
const c = { nested: { d: 4 }, extra: true };

const result = deepMerge(a, b, c);
console.log(JSON.stringify(result));
console.log(JSON.stringify(a));

```javascript
function deepMerge(target, ...sources) {
  // Create a deep copy of the target to avoid mutating the original
  const result = deepClone(target);

  // Merge each source into the result
  for (const source of sources) {
    if (source === null || typeof source !== 'object') {
      continue;
    }

    for (const key in source) {
      if (source[key] === null || typeof source[key] !== 'object') {
        // For primitives or null/undefined, overwrite directly
        result[key] = source[key];
      } else if (Array.isArray(source[key])) {
        // For arrays, concatenate with existing array or create new one
        if (Array.isArray(result[key])) {
          result[key] = result[key].concat(source[key]);
        } else {
          result[key] = [...source[key]];
        }
      } else {
        // For objects, recursively merge
        if (result[key] && typeof result[key] === 'object' && !Array.isArray(result[key])) {
          result[key] = deepMerge(result[key], source[key]);
        } else {
          result[key] = deepClone(source[key]);
        }
      }
    }
  }

  return result;
}

function deepClone(obj) {
  if (obj === null || typeof obj !== 'object') {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => deepClone(item));
  }

  const clonedObj = {};
  for (const key in obj) {
    if (obj.hasOwnProperty(key)) {
      clonedObj[key] = deepClone(obj[key]);
    }
  }

  return clonedObj;
}

// Test code
const a = { x: 1, nested: { a: 1, b: [1, 2] }, arr: [1] };
const b = { x: 2, nested: { b: [3, 4], c: 3 }, arr: [2, 3] };
const c = { nested: { d: 4 }, extra: true };

const result = deepMerge(a, b, c);
console.log(JSON.stringify(result));
console.log(JSON.stringify(a));
```
